class _HybridWebViewPageState extends State<HybridWebViewPage> {
  late final WebViewController _controller;
  bool _isLoading = true;

  static const String _mobileWebsiteUrl = 'https://your-mobile-website.com';

  @override
  void initState() {
    super.initState();

    _controller =
        WebViewController()
          ..setJavaScriptMode(JavaScriptMode.unrestricted)
          ..setNavigationDelegate(
            NavigationDelegate(
              onPageStarted: (_) {
                setState(() => _isLoading = true);
              },
              onPageFinished: (_) {
                setState(() => _isLoading = false);
              },
              onWebResourceError: (error) {
                debugPrint('WebView error: ${error.description}');
              },
            ),
          )
          ..addJavaScriptChannel(
            'FlutterBridge',
            onMessageReceived: (JavaScriptMessage message) {
              _handleJavaScriptMessage(message.message);
            },
          )
          ..loadRequest(Uri.parse(_mobileWebsiteUrl));
  }

  Future<void> _handleJavaScriptMessage(String message) async {
    debugPrint('Message from web: $message');

    switch (message) {
      case 'openCamera':
        _openCamera();
        break;
      case 'registerPush':
        _registerPushNotifications();
        break;
      default:
        _showSnackBar('Web says: $message');
